// Worked focus: http-ts-sensitive-field-forwarding — Strip or deliberately reissue authorization, cookies, origin-sensitive fields, and bodies when authority changes. Demonstrate the result through TypeScript 7 strict types plus WHATWG Fetch Request, Response, Headers, URL, streams, and AbortSignal contracts.
function worked_http_ts_redirects_policy_4(status: number, sameOrigin: boolean, hop: number, hasCredentials: boolean): { follow: boolean; preserveMethod: boolean; forwardCredentials: boolean } {
  const preserveMethod = status === 307 || status === 308;
  if (hop < 0 || hop >= 8) return { follow: false, preserveMethod, forwardCredentials: false };
  const redirectStatus = status >= 300 && status < 400;
  return {
    follow: redirectStatus,
    preserveMethod,
    forwardCredentials: redirectStatus && sameOrigin && hasCredentials,
  };
}

